SELECT regulatory_entity
FROM regulations
WHERE status = 'active' AND expiration_date IS NULL;

SELECT entity_id, entity_name
FROM regulatory_entities
WHERE entity_name = 'Corps of Engineers, Department of the Army, Department of Defense';

SELECT subject_name
FROM rule_subjects
WHERE subject_id = 0;

SELECT domain_name, description
FROM regulatory_domains
WHERE domain_id = 1;

SELECT domain_name
FROM regulatory_domains
WHERE description LIKE '%Health%';

SELECT entity_name
FROM regulatory_entities
WHERE entity_id = 0;

SELECT domain_name
FROM regulatory_domains
ORDER BY domain_name ASC;
